const APP_TOKEN = "YOUR_FEISHU_BASE_TOKEN";
const PRODUCT_TABLE = "YOUR_PRODUCT_TABLE_ID";
const HOOK_TABLE = "YOUR_HOOK_TABLE_ID";
const SCRIPT_TABLE = "YOUR_SCRIPT_TABLE_ID";
const VIDEO_TABLE = "YOUR_VIDEO_TABLE_ID";
const SETTINGS_TABLE = 'YOUR_OPTIONAL_SETTINGS_TABLE_ID';
const FEISHU_APP_ID = 'YOUR_FEISHU_APP_ID';
const FEISHU_APP_SECRET = String($env.FEISHU_APP_SECRET || '');
const NL = String.fromCharCode(10);
const httpRequest = (options) => this.helpers.httpRequest(options);

async function requestJson(options, label) {
  const response = await httpRequest({
    ...options,
    json: true,
    simple: false,
    resolveWithFullResponse: true,
    timeout: options.timeout || 120000,
  });
  const statusCode = response.statusCode || response.status || 200;
  const body = response.body ?? response;
  if (statusCode < 200 || statusCode >= 300) {
    throw new Error(label + ' HTTP ' + statusCode + ': ' + JSON.stringify(body).slice(0, 1000));
  }
  return body;
}

async function feishuToken() {
  const res = await requestJson({
    method: 'POST',
    url: 'https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal',
    headers: { 'Content-Type': 'application/json' },
    body: { app_id: FEISHU_APP_ID, app_secret: FEISHU_APP_SECRET },
  }, '飞书取 token');
  if (!res.tenant_access_token) throw new Error('飞书 token 为空。');
  return res.tenant_access_token;
}

async function getRecord(token, tableId, recordId) {
  const res = await requestJson({
    method: 'GET',
    url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records/' + recordId,
    headers: { Authorization: 'Bearer ' + token },
  }, '飞书读记录');
  return res?.data?.record;
}

async function listRecords(token, tableId, pageSize = 100) {
  const res = await requestJson({
    method: 'GET',
    url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records?page_size=' + pageSize,
    headers: { Authorization: 'Bearer ' + token },
  }, '飞书列记录');
  return res?.data?.items || [];
}

async function updateRecord(token, tableId, recordId, fields) {
  await requestJson({
    method: 'PUT',
    url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records/' + recordId,
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json; charset=utf-8' },
    body: { fields },
  }, '飞书更新记录');
}

async function createRecord(token, tableId, fields) {
  const res = await requestJson({
    method: 'POST',
    url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records',
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json; charset=utf-8' },
    body: { fields },
  }, '飞书创建记录');
  const id = res?.data?.record?.record_id;
  if (!id) throw new Error('飞书创建记录无 record_id: ' + JSON.stringify(res).slice(0, 800));
  return id;
}

async function batchCreate(token, tableId, records) {
  if (!records.length) return [];
  const res = await requestJson({
    method: 'POST',
    url: 'https://open.feishu.cn/open-apis/bitable/v1/apps/' + APP_TOKEN + '/tables/' + tableId + '/records/batch_create',
    headers: { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json; charset=utf-8' },
    body: { records },
  }, '飞书批量创建记录');
  return res?.data?.records || [];
}

function firstSelect(value) {
  if (Array.isArray(value)) return String(value[0]?.text || value[0]?.name || value[0] || '');
  return String(value || '');
}

function textCell(value) {
  if (Array.isArray(value)) return value.map((x) => x?.text || x?.name || x).join('');
  if (value && typeof value === 'object') return value.text || value.link || '';
  return String(value || '');
}

function urlCell(value) {
  if (Array.isArray(value)) return value[0]?.link || value[0]?.text || '';
  if (value && typeof value === 'object') return value.link || value.text || '';
  return String(value || '');
}

function linkIds(value) {
  if (!Array.isArray(value)) return [];
  return value.map((x) => x?.record_id || x?.id || x?.record_ids?.[0] || x).filter(Boolean);
}

function extractJson(text) {
  if (typeof text !== 'string') return text;
  const cleaned = text.replace(/^\s*\`\`\`(?:json)?/i, '').replace(/\`\`\`\s*$/i, '').trim();
  try { return JSON.parse(cleaned); } catch {}
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first >= 0 && last > first) return JSON.parse(cleaned.slice(first, last + 1));
  throw new Error('无法解析 JSON: ' + cleaned.slice(0, 500));
}

async function getModelConfig(token) {
  const rows = await listRecords(token, SETTINGS_TABLE, 20);
  const enabled = rows.find((r) => firstSelect(r.fields['是否启用']) === '是') || rows[0];
  const provider = firstSelect(enabled?.fields?.['LLM Provider']) || 'DeepSeek';
  const model = textCell(enabled?.fields?.['模型名称']) || 'deepseek-chat';
  const baseUrl = urlCell(enabled?.fields?.['OpenAI兼容Base URL']) || 'https://api.deepseek.com';
  let key = '';
    if (provider === 'DeepSeek') key = String($env.DEEPSEEK_API_KEY || '').trim();
  if (provider === 'OpenAI') key = String($env.OPENAI_API_KEY || '').trim();
  if (!key) throw new Error('缺少 ' + provider + ' API key，请在 n8n .env / credential 中配置。');
  return { provider, model, baseUrl: baseUrl.replace(/\/$/, ''), key };
}

async function llm(token, system, user, { json = false, temperature = 0.55, maxTokens = 5000 } = {}) {
  const cfg = await getModelConfig(token);
  const body = {
    model: cfg.model,
    messages: [{ role: 'system', content: system }, { role: 'user', content: user }],
    temperature,
    max_tokens: maxTokens,
  };
  if (json) body.response_format = { type: 'json_object' };
  const response = await requestJson({
    method: 'POST',
    url: cfg.baseUrl + '/chat/completions',
    headers: { Authorization: 'Bearer ' + cfg.key, 'Content-Type': 'application/json' },
    body,
  }, cfg.provider + ' LLM');
  const content = response?.choices?.[0]?.message?.content;
  if (!content) throw new Error(cfg.provider + ' 返回空内容: ' + JSON.stringify(response).slice(0, 600));
  if (!json) return { text: String(content).trim(), config: cfg };
  try {
    return { json: extractJson(content), config: cfg };
  } catch (error) {
    const repair = await requestJson({
      method: 'POST',
      url: cfg.baseUrl + '/chat/completions',
      headers: { Authorization: 'Bearer ' + cfg.key, 'Content-Type': 'application/json' },
      body: {
        model: cfg.model,
        messages: [
          { role: 'system', content: 'You repair malformed JSON. Return only valid JSON. Do not explain.' },
          { role: 'user', content: 'Repair this into valid JSON:\n\n' + content },
        ],
        temperature: 0,
        max_tokens: maxTokens,
        response_format: { type: 'json_object' },
      },
    }, cfg.provider + ' JSON repair');
    return { json: extractJson(repair?.choices?.[0]?.message?.content || ''), config: cfg };
  }
}

