function urlValue(url) {
  return url ? { text: url, link: url } : null;
}

function parseResultUrls(resultJson) {
  if (!resultJson) return [];
  let parsed = resultJson;
  if (typeof parsed === 'string') {
    try { parsed = JSON.parse(parsed); } catch { return []; }
  }
  const candidates = [parsed.resultUrls, parsed.result_urls, parsed.urls, parsed.imageUrls, parsed.videoUrls];
  for (const c of candidates) if (Array.isArray(c) && c.length) return c.map(String);
  if (typeof parsed.url === 'string') return [parsed.url];
  return [];
}

const query = $('Webhook: Create Video Task').first().json.query || {};
const scriptRecordId = String(query.script_record_id || '').trim();
if (!scriptRecordId) throw new Error('缺少 script_record_id');
const token = await feishuToken();
const script = await getRecord(token, SCRIPT_TABLE, scriptRecordId);
if (!script) throw new Error('找不到脚本记录');
const productId = linkIds(script.fields['关联产品'])[0];
const hookId = linkIds(script.fields['关联Hook'])[0];
if (!productId || !hookId) throw new Error('脚本缺少产品或 Hook 关联');
const product = await getRecord(token, PRODUCT_TABLE, productId);
const videoId = await createRecord(token, VIDEO_TABLE, {
  '视频标题': String(textCell(script.fields['脚本标题']) || 'UGC视频任务').slice(0, 100),
  '产品链接': urlValue(urlCell(product.fields['产品链接'])),
  '视频状态': '待补素材',
  '语言': firstSelect(script.fields['语言']) || '中文',
  '产品图URL': urlValue(urlCell(product.fields['产品主图URL'])),
  '产品图来源说明': '默认带入产品主图；可在视频任务中上传附件或替换 URL。',
  '关联产品': [productId],
  '关联Hook': [hookId],
  '关联脚本': [scriptRecordId],
});
await updateRecord(token, SCRIPT_TABLE, scriptRecordId, { '确认状态': '已确认' });
return [{ json: { message: 'Video task created', scriptRecordId, videoId } }];

